+      `solutions/platform/${directImportSlug}.json`,
+      `solutions/install/${directImportSlug}.json`,
+    ]
+
+    const tryImport = async () => {
+      for (const path of paths) {
+        try {
+          const res = await fetch(`/api/missions/file?path=${encodeURIComponent(path)}`)
